from flask import Flask, jsonify, request
from pymemcache.client import base as memcache_base
import time

app = Flask(__name__)
memcached = memcache_base.Client(('localhost', 11211))

@app.route('/api/dbquery')
def dbquery():
    cached_data = memcached.get('api_result')
    
    if not cached_data:
        # Simulating a long running DB Query
        time.sleep(5)
        
        data = "Query Result" 
        memcached.set('api_result', data, timeout=60)   # Cache the result for 1 minute
        
        return jsonify({'response': data}), 200
    
    return jsonify({'response': cached_data.decode()}), 200

if __name__ == '__main__':
    app.run(port=5000, debug=True)